from typing import Type, List

from geosat.psanp.abstractions.stage import Stage
from geosat.psanp.abstractions.stages import register_stage

from psanp.classifiers.augmentation_classifier import AugmentationClassifier
from psanp.classifiers.cadastre_classifier import CadastreClassifier
from psanp.classifiers.ground_classifier import GroundClassifier
from psanp.classifiers.interior_classifier import InteriorClassifier
from psanp.classifiers.lane_mark_segmenter import LaneMarkSegmenter
from psanp.classifiers.noise_classifier import NoiseClassifier
from psanp.classifiers.reset_classifier import ResetClassifier
from psanp.classifiers.slice_classifier import SliceClassifier
from psanp.classifiers.smooth_ground_classifier import SmoothGroundClassifier
from psanp.classifiers.subsample_classifier import SubsampleClassifier
from psanp.classifiers.urban_ground_classifier import UrbanGroundClassifier
from psanp.stages.class_selector import ClassSelectorStage
from psanp.stages.geotiff_writer import GeoTiffWriter
from psanp.stages.reprojection import ReprojectionStage
from psanp.stages.writer import NullWriter, CloudSaver

_STANDARD_STAGES: List[Type[Stage]] = [
    ResetClassifier,
    GroundClassifier,
    SmoothGroundClassifier,
    UrbanGroundClassifier,
    CadastreClassifier,
    NoiseClassifier,
    LaneMarkSegmenter,
    NullWriter,
    CloudSaver,
    GeoTiffWriter,
    SliceClassifier,
    ReprojectionStage,
    ClassSelectorStage,
    SubsampleClassifier,
    AugmentationClassifier,
    InteriorClassifier,
]


def register_standard_stages() -> None:
    """Register the stages that are locally available in the ``psanp`` package"""
    for stage in _STANDARD_STAGES:
        register_stage(stage)
